const awsServices = [
  { name: "SES", Icon: AwsSesIcon },
  { name: "Lambda", Icon: AwsLambdaIcon },
  { name: "EventBridge", Icon: AwsEventbridgeIcon },
  { name: "DynamoDB", Icon: AwsDynamodbIcon },
];

function GridPattern() {
  return (
    <svg
      className="absolute inset-0 size-full opacity-[0.04] dark:opacity-[0.03]"
      xmlns="http://www.w3.org/2000/svg"
    >
      <defs>
        <pattern
          height="32"
          id="trusted-by-grid"
          patternUnits="userSpaceOnUse"
          width="32"
        >
          <path
            d="M0 32V0h32"
            fill="none"
            stroke="currentColor"
            strokeWidth="1"
          />
        </pattern>
      </defs>
      <rect fill="url(#trusted-by-grid)" height="100%" width="100%" />
    </svg>
  );
}

function DotGrid() {
  const rows = 8;
  const cols = 12;

  return (
    <div className="absolute -right-4 -top-4">
      <div
        className="grid gap-3"
        style={{ gridTemplateColumns: `repeat(${cols}, 1fr)` }}
      >
        {Array.from({ length: rows * cols }).map((_, i) => {
          const row = Math.floor(i / cols);
          const col = i % cols;

          // Top-right corner: fade as we go down-left
          const distance = (row + (cols - 1 - col)) / (rows + cols - 2);
          const opacity = Math.max(0, 1 - distance * 1.2);

          if (opacity <= 0.05) return <div className="size-1" key={i} />;

          return (
            <div
              className="size-1 rounded-full bg-orange-500 dark:bg-orange-400"
              key={i}
              style={{ opacity: opacity * 0.5 }}
            />
          );
        })}
      </div>
    </div>
  );
}

// AWS with services component - AWS logo with service icons next to it
function AWSWithServices() {
  return (
    <div className="flex items-center gap-3">
      <Tooltip>
        <TooltipTrigger asChild>
          <a
            aria-label="Learn more about AWS"
            className="transition-opacity hover:opacity-70"
            href="https://aws.amazon.com"
            rel="noopener noreferrer"
            target="_blank"
          >
            <AWSLogo className="h-10 w-auto text-muted-foreground transition-colors hover:text-foreground sm:h-12" />
          </a>
        </TooltipTrigger>
        <TooltipContent>AWS</TooltipContent>
      </Tooltip>

      {/* Divider */}
      <div className="h-8 w-px bg-border/50" />

      {/* Service icons */}
      <div className="flex items-center gap-2">
        {awsServices.map((service) => (
          <Tooltip key={service.name}>
            <TooltipTrigger asChild>
              <span>
                <service.Icon className="size-7 text-muted-foreground/50 sm:size-8" />
              </span>
            </TooltipTrigger>
            <TooltipContent>{service.name}</TooltipContent>
          </Tooltip>
        ))}
      </div>
    </div>
  );
}

